```typescript
class TokenBucket {
    private tokens: number;
    private readonly capacity: number;
    private readonly refillRate: number; // tokens per second
    private lastRefillTimestamp: number;

    constructor(capacity: number, refillRate: number) {
        this.capacity = capacity;
        this.refillRate = refillRate;
        this.tokens = capacity;
        this.lastRefillTimestamp = Date.now();
    }

    private refill(): void {
        const now = Date.now();
        const elapsedTime = (now - this.lastRefillTimestamp) / 1000;
        const tokensToAdd = elapsedTime * this.refillRate;
        this.tokens = Math.min(this.tokens + tokensToAdd, this.capacity);
        this.lastRefillTimestamp = now;
    }

    async consume(tokens: number): Promise<void> {
        return new Promise((resolve, reject) => {
            const checkAndConsume = () => {
                this.refill();
                if (this.tokens >= tokens) {
                    this.tokens -= tokens;
                    resolve();
                } else {
                    setTimeout(checkAndConsume, 10); // retry after 10ms
                }
            };
            checkAndConsume();
        });
    }
}

// Usage example:
(async () => {
    const rateLimiter = new TokenBucket(5, 1); // 5 tokens, refilled at 1 token per second

    try {
        await rateLimiter.consume(3);
        console.log('Request processed');
        await rateLimiter.consume(2);
        console.log('Request processed');
        await rateLimiter.consume(1);
        console.log('Request processed'); // This will wait until a token is available
    } catch (error) {
        console.error('Error:', error);
    }
})();
```

Ce code implémente un `TokenBucket` asynchrone en TypeScript qui limite le taux de consommation de ressources. Le `TokenBucket` est initialisé avec une capacité maximale de jetons et un taux de remplissage. La méthode `consume` tente de consommer un certain nombre de jetons et attend si nécessaire jusqu'à ce qu'il y ait suffisamment de jetons disponibles.

